    {
      "type": "codeBlock",
      "content": [
        {
          "type": "text",
          "text": "function selectActivities(intervals) {\n  // intervals: [{ start: number, end: number }]\n  intervals.sort((a, b) => a.end - b.end);\n  const result = [];\n  let currentEnd = -Infinity;\n  for (const it of intervals) {\n    if (it.start >= currentEnd) {\n      result.push(it);\n      currentEnd = it.end;\n    }\n  }\n  return result; // Максимальное по размеру множество непересекающихся интервалов\n}\n\n// Пример\nconst intervals = [\n  { start: 1, end: 3 },\n  { start: 2, end: 5 },\n  { start: 0, end: 6 },\n  { start: 5, end: 7 },\n  { start: 8, end: 9 },\n  { start: 5, end: 9 }\n];\nconsole.log(selectActivities(intervals));\n// Сложность: O(n log n) из-за сортировки; доказательство — через аргумент обмена."
        }
