    {
      "type": "codeBlock",
      "content": [
        {
          "type": "text",
          "text": "def greedy_change(amount, coins):\n    coins = sorted(coins, reverse=True)\n    result = []\n    for c in coins:\n        cnt = amount // c\n        if cnt > 0:\n            result.append((c, cnt))\n            amount -= cnt * c\n    return result\n\n# Пример\nprint(greedy_change(28, [1, 2, 5, 10]))\n# Вывод: [(10, 2), (5, 1), (2, 1), (1, 1)]\n# Примечание: для произвольных номиналов жадный подход может быть неоптимальным."
        }
      ]
    },

