        { "type": "listItem", "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Назовите случаи применимости (интервалы, MST, Дейкстра ≥ 0, Хаффман)." }] }] },
        { "type": "listItem", "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Приведите контрпример, где жадность ломается (рюкзак 0/1, монеты [1,3,4])." }] }] },
        { "type": "listItem", "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Кратко опишите доказательство через аргумент обмена." }] }] }
      ]
    }
