];
console.log(selectActivities(activities));"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Контрпример: размен монет (жадность ломается)"}]},{"type":"paragraph","content":[{"type":"text","text":"Для монет [1, 3, 4] и суммы 6 жадность (брать самую большую монету ≤ остатка) даёт не оптимальный ответ."}]},{"type":"codeBlock","attrs":{"language":"js"},"content":[{"type":"text","text":"function coinChangeGreedy(amount, coins) {
  coins = [...coins].sort((a, b) => b - a);
  const used = [];
  for (const c of coins) {
    while (amount >= c) {
      amount -= c;
      used.push(c);
    }
  }
  return amount === 0 ? used : null; // null, если размен невозможен
}

function coinChangeDP(amount, coins) {
  const dp = Array(amount + 1).fill(Infinity);
  const prev = Array(amount + 1).fill(-1);
  dp[0] = 0;
  for (let a = 1; a <= amount; a++) {
    for (const c of coins) {
      if (a >= c && dp[a - c] + 1 < dp[a]) {
        dp[a] = dp[a - c] + 1;
        prev[a] = c;
      }
    }
  }
  if (!isFinite(dp[amount])) return null;
  const res = [];
  for (let a = amount; a > 0; a -= prev[a]) res.push(prev[a]);
  return res;
}

const coins = [1, 3, 4];
const amount = 6;
console.log('Greedy:', coinChangeGreedy(amount, coins)); // [4, 1, 1]
console.log('DP    :', coinChangeDP(amount, coins));     // [3, 3] (оптимум)"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Итог"}]},{"type":"paragraph","content":[{"type":"text","text":"Локально оптимальный выбор — это «лучший шаг сейчас» по заданному критерию. Жадные алгоритмы быстры и просты, но дают корректный глобально оптимальный результат только для задач с подходящей структурой (greedy-choice property и оптимальная подструктура). Для остальных задач нужна динамика, перебор или другой подход."}]}]}

