    {
      "type": "codeBlock",
      "content": [
        {
          "type": "text",
          "text": "// intervals: массив объектов { start, end }\nfunction selectActivities(intervals) {\n  // 1) Сортируем по времени окончания\n  intervals.sort((a, b) => a.end - b.end);\n\n  const result = [];\n  let lastEnd = -Infinity;\n\n  // 2) Идем слева направо, добавляя первый совместимый интервал\n  for (const it of intervals) {\n    if (it.start >= lastEnd) {\n      result.push(it);\n      lastEnd = it.end;\n    }\n  }\n  return result; // максимальный по размеру набор непересекающихся интервалов\n}\n\n// Пример\nconst input = [\n  { start: 1, end: 4 },\n  { start: 3, end: 5 },\n  { start: 0, end: 6 },\n  { start: 5, end: 7 },\n  { start: 8, end: 9 },\n  { start: 5, end: 9 },\n];\nconsole.log(selectActivities(input));"
