          "type": "text",
          "text": "# 1) Сдача монет: жадный против оптимального (DP)\n\ndef greedy_change(amount, coins):\n    coins = sorted(coins, reverse=True)\n    res = []\n    for c in coins:\n        while amount >= c:\n            amount -= c\n            res.append(c)\n    return res\n\n\ndef optimal_change(amount, coins):\n    INF = 10**9\n    dp = [0] + [INF] * amount\n    prev = [-1] * (amount + 1)\n    for a in range(1, amount + 1):\n        for c in coins:\n            if a >= c and dp[a - c] + 1 < dp[a]:\n                dp[a] = dp[a - c] + 1\n                prev[a] = c\n    if dp[amount] >= INF:\n        return None\n    res = []\n    a = amount\n    while a > 0:\n        res.append(prev[a])\n        a -= prev[a]\n    return res\n\ncoins = [1, 3, 4]\namount = 6\nprint(\"Greedy:\", greedy_change(amount, coins), \"count=\", len(greedy_change(amount, coins)))\nopt = optimal_change(amount, coins)\nprint(\"Optimal:\", opt, \"count=\", len(opt))\n\n# 2) 0/1 рюкзак: жадность по v/w\n\ndef greedy_knapsack(capacity, items):\n    # items: list of (value, weight, name)\n    items_sorted = sorted(items, key=lambda x: x[0] / x[1], reverse=True)\n    value = 0\n    weight = 0\n    chosen = []\n    for v, w, name in items_sorted:\n        if weight + w <= capacity:\n            weight += w\n            value += v\n            chosen.append(name)\n    return value, chosen\n\nitems = [(60, 10, 'A'), (100, 20, 'B'), (120, 30, 'C')]\nprint(\"Greedy knapsack:\", greedy_knapsack(50, items))  # -> (160, ['A', 'B'])\nprint(\"Optimal value should be 220 with ['B','C']\")"
